CREATE TABLE IF NOT EXISTS "Home" ("id" TEXT NOT NULL PRIMARY KEY, "name" TEXT NOT NULL DEFAULT 'Home', "inviteCode" TEXT NOT NULL, "person1" TEXT NOT NULL, "person2" TEXT, "person1SeenAt" DATETIME, "person2SeenAt" DATETIME, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX IF NOT EXISTS "Home_inviteCode_key" ON "Home"("inviteCode");
CREATE TABLE IF NOT EXISTS "Entry" ("id" TEXT NOT NULL PRIMARY KEY, "content" TEXT NOT NULL, "authorName" TEXT NOT NULL, "homeId" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" DATETIME NOT NULL, "deletedAt" DATETIME, FOREIGN KEY ("homeId") REFERENCES "Home"("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "Corner" ("id" TEXT NOT NULL PRIMARY KEY, "icon" TEXT NOT NULL, "name" TEXT NOT NULL, "homeId" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("homeId") REFERENCES "Home"("id") ON DELETE RESTRICT ON UPDATE CASCADE);
CREATE TABLE IF NOT EXISTS "EntryCorner" ("entryId" TEXT NOT NULL, "cornerId" TEXT NOT NULL, "createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY ("entryId", "cornerId"), FOREIGN KEY ("entryId") REFERENCES "Entry"("id") ON DELETE RESTRICT ON UPDATE CASCADE, FOREIGN KEY ("cornerId") REFERENCES "Corner"("id") ON DELETE RESTRICT ON UPDATE CASCADE);
